from typing import List, Dict, Any
from pydantic import BaseModel

class NestedPlan(BaseModel):
    tasks: List[Dict[str, Any]]

    @validator('tasks')
    def check_depth_consistency(cls, tasks):
        depths = [len(find_nested_depth(task)) for task in tasks]
        if max(depths) - min(depths) > 1:
            raise ValueError(f'Inconsistent nesting depth: {depths}')
        return tasks

def find_nested_depth(obj: Dict) -> int:
    if not isinstance(obj, dict):
        return 0
    return 1 + max([find_nested_depth(v) for v in obj.values()], default=0)

