class CoordinationClient:
    def __init__(self):
        self.client = Instructor(client=OpenAI())

    @backoff(attempts=3, wait=2**3)
    def safe_extract(self, messages, mode='strict'):
        if mode == 'strict':
            return self.client.messages.create(
                model='gpt-4o-mini',
                response_model=CoordinatedOutput,
                messages=messages
            )
        else:
            # FALLBACK: partial model
            return self.client.messages.create(
                model='gpt-4o-mini',
                response_model=PartialOutput,  # less strict
                messages=messages
            )

# Usage
